  it('should not treat a non-function object with length 1 as a partial sink creator', () => {
    const sourceObj = { length: 1, source: (read: any) => read };

    const result = pull(sourceObj);

    // Original code: typeof sourceObj === 'function' is false, so skip partial sink branch
    // It then checks sourceObj.source is a function, sets read = sourceObj.source
    // Returns sourceObj.source directly
    // 
    // Mutated code: true && sourceObj.length === 1 is true, enters partial sink branch
    // Returns a closure function (partial sink), NOT sourceObj.source

    expect(result).toBe(sourceObj.source);
